import SwiftUI
import Combine

class Portfolio: ObservableObject {
    @Published var stocks: [Stock] = []
}

class Stock: Identifiable {
    let id: UUID = UUID()
    var symbol: String
    var price: Double
    var quantity: Int
}

class TradeManager: ObservableObject {
    @Published var isExecutingTrade = false
    @Published var errorMessage: String?

    func executeTrade(stock: Stock, quantity: Int) {
        // API call to execute trade
        // ...

        if successful {
            // Update portfolio
            let existingStock = portfolio.stocks.first(where: { $0.symbol == stock.symbol })
            if let existingStock {
                existingStock.quantity += quantity
            } else {
                let newStock = Stock(symbol: stock.symbol, price: stock.price, quantity: quantity)
                portfolio.stocks.append(newStock)
            }
        } else {
            errorMessage = "Failed to execute trade"
        }
    }
}

struct PortfolioView: View {
    @ObservedObject var portfolio: Portfolio

    var body: some View {
        List {
            ForEach(portfolio.stocks) { stock in
                StockRow(stock: stock)
            }
        }
    }
}

struct StockRow: View {
    let stock: Stock

    var body: some View {
        HStack {
            Text(stock.symbol)
            Text("\(stock.price)")
            Text("\(stock.quantity)")
        }
    }
}

struct TradeView: View {
    @ObservedObject var tradeManager: TradeManager
    @State private var symbol: String
    @State private var quantity: Int

    var body: some View {
        VStack {
            TextField("Symbol", text: $symbol)
            TextField("Quantity", value: $quantity, formatter: NumberFormatter())
            Button("Execute Trade") {
                tradeManager.executeTrade(stock: Stock(symbol: symbol, price: 0, quantity: 0), quantity: quantity)
            }
            .disabled(tradeManager.isExecutingTrade)
            Text(tradeManager.errorMessage ?? "")
        }
    }
}